import csv


def write_csv(data: list[dict], path: str) -> None:
    if not data:
        return
    try:
        with open(path, "w", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=data[0].keys())
            writer.writeheader()
            writer.writerows(data)
    except IOError as e:
        raise IOError(f"Failed to write CSV: {e}")
