def load_env(path: str = ".env") -> dict[str, str]:
    env_vars = {}
    try:
        with open(path) as f:
            for line in f:
                line = line.strip()
                if line and not line.startswith("#") and "=" in line:
                    key, _, value = line.partition("=")
                    env_vars[key.strip()] = value.strip().strip('"')
    except FileNotFoundError:
        pass
    return env_vars
