import csv


def merge_csv(file_a: str, file_b: str, key: str) -> list[dict]:
    try:
        with open(file_a) as fa, open(file_b) as fb:
            rows_a = {r[key]: r for r in csv.DictReader(fa)}
            for r in csv.DictReader(fb):
                if r[key] in rows_a:
                    rows_a[r[key]].update(r)
        return list(rows_a.values())
    except FileNotFoundError as e:
        raise FileNotFoundError(f"File not found: {e}")
```

