from pathlib import Path


def files_by_size(directory: str) -> list[tuple[str, int]]:
    try:
        files = [(str(p), p.stat().st_size) for p in Path(directory).iterdir() if p.is_file()]
        return sorted(files, key=lambda x: x[1], reverse=True)
    except OSError as e:
        raise OSError(f"Cannot list directory: {e}")
